import { GoogleGenAI, Type } from "@google/genai";
import { ArtifactType, GeneratedArtifact } from '../types';

const API_KEY = process.env.API_KEY;
if (!API_KEY) {
    throw new Error("API_KEY environment variable not set");
}

const ai = new GoogleGenAI({ apiKey: API_KEY });

const safeParseJson = (jsonString: string): any => {
    // Attempt to find JSON within markdown code fences
    const match = jsonString.match(/```(json)?\s*([\s\S]*?)\s*```/);
    let textToParse = jsonString.trim();

    if (match && match[2]) {
        textToParse = match[2];
    } else {
        // Fallback for cases where there are no code fences, but maybe leading/trailing text
        const firstBrace = textToParse.indexOf('{');
        const lastBrace = textToParse.lastIndexOf('}');
        if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
            textToParse = textToParse.substring(firstBrace, lastBrace + 1);
        }
    }

    try {
        let parsed = JSON.parse(textToParse);
        // Handle cases where the model returns a stringified JSON object
        if (typeof parsed === 'string') {
            parsed = JSON.parse(parsed);
        }
        return parsed;
    } catch (error) {
        console.error("Failed to parse JSON:", textToParse);
        throw new Error("Received invalid JSON from the model.");
    }
};

const getObservationSummary = async (context: string): Promise<GeneratedArtifact> => {
    const prompt = `Atue como um Especialista em UX Research Sênior. Sua tarefa é analisar as notas de observação fornecidas e criar um relatório de síntese estruturado.

O relatório deve conter as seguintes seções em Markdown:
1. **Contexto e Ambiente**: Onde e quando a observação ocorreu? O que estava acontecendo ao redor?
2. **Comportamentos Chave**: O que o usuário fez? Descreva as ações sequencialmente ou por relevância.
3. **Pontos de Dor (Pain Points)**: Quais dificuldades, barreiras ou frustrações o usuário encontrou?
4. **Gambiarra/Soluções de Contorno**: O usuário inventou alguma maneira não oficial de resolver um problema?
5. **Oportunidades de Design**: Com base no que foi visto, quais são as oportunidades imediatas de melhoria?

Contexto da Observação:
${context}`;
    const response = await ai.models.generateContent({
        model: "gemini-2.5-flash",
        contents: prompt
    });
    return { text: response.text };
};

const getInterviewQuestions = async (context: string): Promise<GeneratedArtifact> => {
    const prompt = `Atue como um Especialista em UX Research. Com base no contexto fornecido, crie um roteiro de entrevista semi-estruturado.

O objetivo é aprofundar o entendimento sobre as motivações e problemas do usuário.
Estruture a resposta em Markdown com as seguintes categorias:

1. **Quebra-Gelo e Introdução**: 3-4 perguntas para deixar o participante à vontade e entender seu perfil básico.
2. **Exploração do Problema/Tarefa**: Perguntas abertas ("Conte-me sobre a última vez que...", "Como você lida com...") focadas em fatos e comportamentos passados, não em opiniões futuras.
3. **Aprofundamento (Os 'Porquês')**: Perguntas de follow-up para entender a raiz das frustrações.
4. **Encerramento**: Perguntas finais para capturar algo que não foi coberto.

Evite perguntas de "sim/não". Priorize perguntas que evoquem histórias.

Contexto do Projeto:
${context}`;
    const response = await ai.models.generateContent({
        model: "gemini-2.5-flash",
        contents: prompt
    });
    return { text: response.text };
};

const getEmpathyMap = async (context: string): Promise<GeneratedArtifact> => {
    const prompt = `Atue como um UX Designer. Crie um Mapa de Empatia detalhado e profundo para a persona principal deste projeto. Use todo o contexto disponível.

A saída deve ser formatada estritamente em Markdown, cobrindo os seguintes quadrantes (use listas com bullets):

1. **O QUE ELA VÊ?** (Ambiente, ofertas do mercado, o que os amigos fazem)
2. **O QUE ELA OUVE?** (O que amigos, chefe e influenciadores dizem)
3. **O QUE ELA PENSA E SENTE?** (Preocupações, aspirações, o que realmente importa mas ela não diz)
4. **O QUE ELA FALA E FAZ?** (Atitude em público, aparência, comportamento para com os outros)
5. **DORES (PAINS)** (Medos, frustrações, obstáculos)
6. **GANHOS (GAINS)** (Desejos, necessidades, medidas de sucesso)

Seja específico e inferencial baseado nos dados, não genérico.

Contexto do Projeto:
${context}`;
     const response = await ai.models.generateContent({
        model: "gemini-2.5-flash",
        contents: prompt
    });
    return { text: response.text };
};

const getPersona = async (context: string): Promise<GeneratedArtifact> => {
    const personaPrompt = `Atue como um UX Strategist. Crie uma Persona detalhada baseada nos dados de pesquisa fornecidos.

A resposta DEVE ser um objeto JSON válido.
O campo "name" deve conter o nome fictício da persona.
O campo "description" deve ser uma string contendo um perfil rico formatado em Markdown, cobrindo:
- **Citação/Lema**
- **Dados Demográficos** (Idade, ocupação, localização, etc)
- **Bio** (Breve história e contexto)
- **Objetivos e Motivações**
- **Frustrações e Barreiras**
- **Marcas e Tecnologia**

Contexto do Projeto: ${context}`;

    let personaData;
    const maxRetries = 2;

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
        try {
            const personaResponse = await ai.models.generateContent({
                model: "gemini-2.5-pro",
                contents: personaPrompt,
                config: {
                    responseMimeType: "application/json",
                    responseSchema: {
                        type: Type.OBJECT,
                        properties: {
                            name: { type: Type.STRING },
                            description: { type: Type.STRING },
                        }
                    }
                }
            });

            const parsedData = safeParseJson(personaResponse.text);

            // Relax validation: We only need a non-empty name, as it might contain the description.
            if (parsedData &&
                typeof parsedData.name === 'string' && parsedData.name.trim()
            ) {
                personaData = parsedData;
                break; // Success, exit loop
            } else {
                 console.warn(`Attempt ${attempt} failed: Incomplete persona data. 'name' field missing or empty.`, parsedData);
            }
        } catch (error) {
            console.error(`Attempt ${attempt} failed with error:`, error);
        }

        if (attempt < maxRetries) {
            console.log(`Retrying persona generation... (${attempt}/${maxRetries})`);
        }
    }

    if (!personaData) {
        console.error("Failed to generate valid persona data after all retries.");
        throw new Error("A resposta do modelo para a persona veio incompleta, mesmo após tentar novamente. Faltou o campo 'name'.");
    }

    const { name, description } = personaData;

    let finalName = name;
    let finalDescription = description || ''; // Handle case where description is null/undefined

    const nameLines = name.split('\n');
    // If 'name' field has multiple lines, assume the first is the name and the rest is part of the description.
    if (nameLines.length > 1) {
        finalName = nameLines[0].replace(/^#\s*/, '').trim();
        const descriptionFromName = nameLines.slice(1).join('\n').trim();

        if(descriptionFromName) {
            // Prepend the description found in the name field to the actual description field.
            finalDescription = `${descriptionFromName}\n\n${finalDescription}`.trim();
        }
    }

    const fullDescription = `# ${finalName}\n\n${finalDescription}`;

    // Return only the text artifact.
    return { text: fullDescription.trim() };
};


const getInterviewSummary = async (context: string): Promise<GeneratedArtifact> => {
    const prompt = `Atue como um UX Researcher. Analise a transcrição da entrevista abaixo e sintetize os achados.

Gere um relatório em Markdown contendo:
1. **Resumo Executivo**: Uma visão geral de 3-4 linhas sobre a entrevista.
2. **Principais Insights**: Descobertas não óbvias que surgiram.
3. **Necessidades do Usuário**: Separe em Necessidades Explícitas (o que ele disse que quer) e Necessidades Implícitas (o que ele precisa mas não sabe expressar).
4. **Citações Marcantes (Verbatim)**: As frases mais impactantes que ilustram os pontos acima.

Transcrição/Contexto:
${context}`;
    const response = await ai.models.generateContent({
        model: "gemini-2.5-flash",
        contents: prompt
    });
    return { text: response.text };
};

const getFunctionalRequirements = async (context: string): Promise<GeneratedArtifact> => {
    const prompt = `Atue como um Product Manager Técnico. Com base nas dores e necessidades identificadas no contexto do projeto, liste os requisitos para a solução digital.

Use Markdown para organizar:

### Requisitos Funcionais (O que o sistema deve fazer)
Liste como User Stories ("Como [usuário], eu quero [ação], para que [benefício]") ou declarações claras de "O sistema deve...".
Priorize usando (Alta), (Média) ou (Baixa) ao final de cada item.

### Requisitos Não Funcionais (Como o sistema deve ser)
Liste restrições de performance, segurança, usabilidade, acessibilidade, etc.

Contexto do Projeto:
${context}`;
    const response = await ai.models.generateContent({
        model: "gemini-2.5-pro",
        contents: prompt
    });
    return { text: response.text };
};

const getUserFlows = async (context: string): Promise<GeneratedArtifact> => {
    const prompt = `Atue como um Arquiteto de Informação. Crie um fluxograma (User Flow) para a jornada principal do usuário descrita no contexto.

A resposta DEVE conter APENAS o código para um diagrama Mermaid do tipo 'graph TD'.

Regras para o diagrama:
- Use nós de decisão (losangos) onde houver escolhas (Sim/Não, Sucesso/Erro).
- Nomeie claramente as ações do usuário e as respostas do sistema.
- Comece com um nó de "Início" e termine com "Fim" ou o objetivo alcançado.
- Mantenha o fluxo lógico e legível.

Coloque o código Mermaid dentro de um bloco de código markdown.

Contexto:
${context}`;
    const response = await ai.models.generateContent({
        model: "gemini-2.5-pro",
        contents: prompt
    });

    const rawText = response.text;
    const match = rawText.match(/```(mermaid)?\s*([\s\S]*?)\s*```/);
    const mermaidCode = match && match[2] ? match[2] : rawText;

    return { text: mermaidCode.trim(), isMermaid: true };
};

const getUIScreens = async (context: string): Promise<GeneratedArtifact> => {
    const uiPrompt = `Atue como um Diretor de Arte de UI Design. Sua tarefa é escrever um prompt de geração de imagem textual altamente detalhado para criar uma tela de interface de alta fidelidade.

Considere as personas, o fluxo e os requisitos.
A resposta DEVE ser um objeto JSON com o campo "imagePrompt".

O "imagePrompt" deve descrever a tela visualmente para um modelo de IA generativa (como Imagen ou Midjourney):
- Descreva o tipo de tela (ex: Dashboard, Login, Feed, Detalhe de Produto).
- Defina o estilo visual (ex: Neomorfismo, Material Design, Minimalista, Dark Mode, Cores vibrantes).
- Descreva elementos específicos: Tipografia (Sans-serif, bold headers), Botões (arredondados, gradiente), Ícones (outline, filled).
- Descreva o conteúdo fictício visível para tornar a tela realista.

Contexto do Projeto: ${context}`;

    let uiData;
    const maxRetries = 2;

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
        try {
            const uiResponse = await ai.models.generateContent({
                model: "gemini-2.5-pro",
                contents: uiPrompt,
                config: {
                  responseMimeType: "application/json",
                  responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                      imagePrompt: { type: Type.STRING },
                    }
                  }
                }
            });

            const parsedData = safeParseJson(uiResponse.text);

            if (parsedData && typeof parsedData.imagePrompt === 'string' && parsedData.imagePrompt.trim()) {
                uiData = parsedData;
                break; // Success
            } else {
                console.warn(`Attempt ${attempt} failed: Invalid UI screen data.`, parsedData);
            }
        } catch (error) {
            console.error(`Attempt ${attempt} failed with error:`, error);
        }

        if (attempt < maxRetries) {
            console.log(`Retrying UI screen generation... (${attempt}/${maxRetries})`);
        }
    }

    if (!uiData) {
        console.error("Failed to generate valid UI screen data after all retries.");
        throw new Error("A resposta do modelo para a tela de UI veio incompleta, mesmo após tentar novamente.");
    }

    const finalImagePrompt = `Mobile app UI screen design, high fidelity, HQ, 4k. ${uiData.imagePrompt}`;

    const imageResponse = await ai.models.generateImages({
        model: 'imagen-4.0-generate-001',
        prompt: finalImagePrompt,
        config: {
          numberOfImages: 1,
          aspectRatio: "9:16",
        }
    });

    const base64Image = imageResponse.generatedImages[0].image.imageBytes;
    const imageUrl = `data:image/png;base64,${base64Image}`;

    return { text: "Aqui está uma proposta de UI para a tela solicitada, baseada em todo o contexto do projeto.", imageUrl };
};

export const generateArtifact = async (artifactType: ArtifactType, context: string): Promise<GeneratedArtifact> => {
    switch (artifactType) {
        case ArtifactType.Observation:
            return getObservationSummary(context);
        case ArtifactType.InterviewQuestions:
            return getInterviewQuestions(context);
        case ArtifactType.SummarizeInterview:
            return getInterviewSummary(context);
        case ArtifactType.Personas:
            return getPersona(context);
        case ArtifactType.EmpathyMap:
            return getEmpathyMap(context);
        case ArtifactType.FunctionalRequirements:
            return getFunctionalRequirements(context);
        case ArtifactType.UserFlows:
            return getUserFlows(context);
        case ArtifactType.UIScreens:
            return getUIScreens(context);
        default:
            throw new Error('Tipo de artefato desconhecido');
    }
};

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { ArtifactType, Message, GeneratedArtifact } from './types';
import { generateArtifact } from './services/geminiService';
import OptionSelector from './components/OptionSelector';
import InputForm from './components/InputForm';
import ArtifactDisplay from './components/ArtifactDisplay';
import LoadingSpinner from './components/LoadingSpinner';
import ChatMessage from './components/ChatMessage';
import AdditionalInfoForm from './components/AdditionalInfoForm';

const App: React.FC = () => {
    const [messages, setMessages] = useState<Message[]>([]);
    const [isLoading, setIsLoading] = useState<boolean>(false);
    const [projectContext, setProjectContext] = useState<string>('');
    const [completedArtifacts, setCompletedArtifacts] = useState<ArtifactType[]>([]);
    const [currentArtifactType, setCurrentArtifactType] = useState<ArtifactType | null>(null);
    const messagesEndRef = useRef<HTMLDivElement>(null);
    const handleOptionSelectRef = useRef<((type: ArtifactType) => void) | null>(null);

    // Ref to hold the latest state to avoid stale closures in callbacks
    const stateRef = useRef({ projectContext, completedArtifacts, currentArtifactType });
    useEffect(() => {
        stateRef.current = { projectContext, completedArtifacts, currentArtifactType };
    });

    const addMessage = useCallback((sender: 'bot' | 'user', content: React.ReactNode): string => {
        const id = `${Date.now()}-${Math.random()}`;
        setMessages(prev => [...prev, { id, sender, content }]);
        return id;
    }, []);

    const updateMessage = useCallback((id: string, content: React.ReactNode) => {
        setMessages(prev => prev.map(m => m.id === id ? { ...m, content } : m));
    }, []);

    const initialBotMessage = useCallback(() => {
         addMessage('bot', 
            <>
                <p className="mb-4">Olá! Sou seu assistente de UX. Selecione um artefato para começar a gerar ou para continuar seu projeto.</p>
                <OptionSelector onSelect={(type) => handleOptionSelectRef.current?.(type)} completedArtifacts={[]} />
            </>
        );
    }, [addMessage]);

    useEffect(() => {
       initialBotMessage();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [initialBotMessage]);

    useEffect(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    }, [messages]);

    const handleGeneration = useCallback(async (artifactType: ArtifactType, context: string, isPrimaryInput: boolean) => {
        setIsLoading(true);
        const loadingMessageId = addMessage('bot', <LoadingSpinner />);
        try {
            const result: GeneratedArtifact = await generateArtifact(artifactType, context);

            if (isPrimaryInput) {
                 setProjectContext(`## ${artifactType}\n\n${result.text}`);
            } else {
                 setProjectContext(prev => `${prev}\n\n---\n\n## ${artifactType}\n\n${result.text}`);
            }

            const newCompletedArtifacts = [...stateRef.current.completedArtifacts, artifactType];
            setCompletedArtifacts(newCompletedArtifacts);

            updateMessage(loadingMessageId, <ArtifactDisplay artifact={result} />);

            addMessage('bot', 
                <>
                    <p className="mb-4">Excelente! O que você gostaria de fazer agora?</p>
                    <OptionSelector onSelect={(type) => handleOptionSelectRef.current?.(type)} completedArtifacts={newCompletedArtifacts} />
                </>
            );

        } catch (error) {
            console.error('Error generating artifact:', error);
            updateMessage(loadingMessageId, <p className="text-red-400">Desculpe, ocorreu um erro ao gerar o artefato. Por favor, tente novamente.</p>);
             addMessage('bot', 
                <>
                    <p className="mb-4">Ocorreu um erro. O que você gostaria de fazer agora?</p>
                    <OptionSelector onSelect={(type) => handleOptionSelectRef.current?.(type)} completedArtifacts={stateRef.current.completedArtifacts} />
                </>
            );
        } finally {
            setIsLoading(false);
        }
    }, [addMessage, updateMessage]);

    const handleInputSubmit = useCallback((context: string) => {
        const artifactType = stateRef.current.currentArtifactType;
        if (!artifactType) return;

        const contextToShow = context.length > 300 ? `${context.substring(0, 300)}...` : context;
        addMessage('user', <pre className="whitespace-pre-wrap font-sans">{contextToShow}</pre>);

        handleGeneration(artifactType, context, true);
    }, [addMessage, handleGeneration]);

    const handleAdditionalInfoSubmit = useCallback((additionalContext: string) => {
        const artifactType = stateRef.current.currentArtifactType;
        if (!artifactType) return;

        if(additionalContext) {
            const contextToShow = additionalContext.length > 300 ? `${additionalContext.substring(0, 300)}...` : additionalContext;
            addMessage('user', <pre className="whitespace-pre-wrap font-sans">{contextToShow}</pre>);
        } else {
            addMessage('user', "(Nenhuma informação adicional)");
        }

        const fullContext = `${stateRef.current.projectContext}\n\n--- INFORMAÇÕES ADICIONAIS DO USUÁRIO ---\n${additionalContext}`;
        handleGeneration(artifactType, fullContext.trim(), false);

    }, [addMessage, handleGeneration]);

    const handleOptionSelect = useCallback((type: ArtifactType) => {
        setCurrentArtifactType(type);
        addMessage('user', `Eu escolho: ${type}`);

        const { projectContext } = stateRef.current;

        // If there is no project context yet, we need the user to provide it.
        if (!projectContext) {
             addMessage('bot', <InputForm artifactType={type} onSubmit={handleInputSubmit} isLoading={isLoading} />);
        } else {
            // If context already exists, we ask for optional additional info.
            addMessage('bot', <AdditionalInfoForm artifactType={type} onSubmit={handleAdditionalInfoSubmit} isLoading={isLoading} />);
        }
    }, [isLoading, addMessage, handleInputSubmit, handleAdditionalInfoSubmit]);

    useEffect(() => {
        handleOptionSelectRef.current = handleOptionSelect;
    }, [handleOptionSelect]);

    return (
        <div className="flex flex-col h-screen bg-zinc-950 text-[#EFEFEF] font-sans">
            <header className="bg-zinc-900/80 backdrop-blur-sm p-4 border-b border-zinc-800 shadow-lg fixed top-0 left-0 right-0 z-10">
                <h1 className="text-xl md:text-2xl font-bold text-center bg-clip-text text-transparent bg-gradient-to-r from-orange-500 to-amber-500">
                    Gerador de Artefatos de UX
                </h1>
            </header>
            <main className="flex-1 overflow-y-auto p-4 pt-24 pb-8">
                <div className="max-w-3xl mx-auto space-y-6">
                    {messages.map((msg) => (
                        <ChatMessage key={msg.id} sender={msg.sender}>
                            {msg.content}
                        </ChatMessage>
                    ))}
                    <div ref={messagesEndRef} />
                </div>
            </main>
        </div>
    );
};

export default App;

import React from 'react';
import { BotIcon, UserIcon } from './Icons';

interface ChatMessageProps {
    sender: 'bot' | 'user';
    children: React.ReactNode;
}

const ChatMessage: React.FC<ChatMessageProps> = ({ sender, children }) => {
    const isBot = sender === 'bot';

    return (
        <div className={`flex items-start gap-4 ${isBot ? '' : 'flex-row-reverse'}`}>
            <div className={`flex-shrink-0 w-8 h-8 rounded-full flex items-center justify-center ${isBot ? 'bg-orange-600' : 'bg-zinc-700'}`}>
                {isBot ? <BotIcon /> : <UserIcon />}
            </div>
            <div className={`max-w-[80%] p-4 rounded-lg ${isBot ? 'bg-zinc-800 rounded-tl-none border border-zinc-700' : 'bg-zinc-900 rounded-tr-none border border-zinc-700'}`}>
                {children}
            </div>
        </div>
    );
};

export default ChatMessage;

