const InputForm: React.FC<InputFormProps> = ({ artifactType, onSubmit, isLoading }) => {
    const [text, setText] = useState('');
    const [fileContent, setFileContent] = useState('');
    const [fileName, setFileName] = useState('');

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        setFileName(file.name);
        const reader = new FileReader();
        reader.onload = (event) => {
            const content = event.target?.result as string;
            setFileContent(content);
        };
        reader.readAsText(file);
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!text && !fileContent) return;
        const combinedContext = `${text}\n\n${fileContent ? `--- Conteúdo do arquivo: ${fileName} ---\n${fileContent}` : ''}`;
        onSubmit(combinedContext.trim());
    };

    const canUploadFile = artifactType === ArtifactType.Observation || artifactType === ArtifactType.SummarizeInterview;

    return (
        <form onSubmit={handleSubmit} className="space-y-4">
            <div>
                <label htmlFor="context-input" className="block text-sm font-medium text-gray-400 mb-2">
                    Forneça o contexto necessário:
                </label>
                <textarea
                    id="context-input"
                    value={text}
                    onChange={(e) => setText(e.target.value)}
                    placeholder={placeholders[artifactType]}
                    rows={8}
                    className="w-full p-3 bg-zinc-900 border border-zinc-700 rounded-md focus:ring-2 focus:ring-orange-500 focus:border-orange-500 transition text-[#EFEFEF]"
                    disabled={isLoading}
                />
            </div>

            {canUploadFile && (
                 <div>
                    <label htmlFor="file-upload" className="block text-sm font-medium text-gray-400 mb-2">
                        Ou envie um arquivo de transcrição (.txt):
                    </label>
                    <input 
                        type="file" 
                        id="file-upload"
                        onChange={handleFileChange} 
                        accept=".txt,text/plain"
                        className="block w-full text-sm text-gray-400 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-orange-600 file:text-white hover:file:bg-orange-700 cursor-pointer"
                        disabled={isLoading}
                    />
                    {fileName && <p className="text-xs text-gray-500 mt-1">Arquivo carregado: {fileName}</p>}
                </div>
            )}

            <button
                type="submit"
                disabled={isLoading || (!text && !fileContent)}
                className="w-full flex justify-center py-2 px-4 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-orange-600 hover:bg-orange-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-orange-500 disabled:bg-zinc-700 disabled:text-gray-500 disabled:cursor-not-allowed"
            >
                {isLoading ? 'Gerando...' : 'Gerar Artefato'}
            </button>
        </form>
    );
};

