import React, { useEffect, useRef } from 'react';
import { GeneratedArtifact } from '../types';

declare global {
    interface Window {
        mermaid?: {
            run: (options: { nodes: Array<Element> }) => void;
        }
    }
}

interface ArtifactDisplayProps {
    artifact: GeneratedArtifact;
}

const ArtifactDisplay: React.FC<ArtifactDisplayProps> = ({ artifact }) => {
    const isUIScreen = artifact.imageUrl && artifact.text.includes("proposta de UI");
    const mermaidRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (artifact.isMermaid && mermaidRef.current && window.mermaid) {
            const mermaidElement = mermaidRef.current.querySelector('.mermaid');
            if (mermaidElement) {
                // The artifact.text from the service is already clean Mermaid code.
                // We update the content and ensure Mermaid re-processes it.
                mermaidElement.innerHTML = artifact.text;
                mermaidElement.removeAttribute('data-processed');
                window.mermaid.run({ nodes: [mermaidElement as HTMLElement] });
            }
        }
    }, [artifact]);

    if (artifact.isMermaid) {
        return (
            <div ref={mermaidRef}>
                <pre className="mermaid language-mermaid bg-zinc-900/50 p-4 rounded-lg text-center border border-zinc-700">
                    {/* The useEffect will populate this */}
                </pre>
            </div>
        );
    }

    return (
        <div className="space-y-4">
            {artifact.imageUrl && (
                <div className={`flex justify-center ${isUIScreen ? 'w-full' : ''}`}>
                    <img
                        src={artifact.imageUrl}
                        alt="Artefato Gerado"
                        className={`rounded-lg shadow-lg object-cover border-4 border-zinc-700 ${isUIScreen ? 'w-full max-w-sm' : 'w-64 h-64'}`}
                    />
                </div>
            )}
            <div className="prose prose-invert prose-sm sm:prose-base max-w-none bg-zinc-900/50 p-4 rounded-lg border border-zinc-700">
                <pre className="whitespace-pre-wrap font-sans text-[#EFEFEF]">{artifact.text}</pre>
            </div>
        </div>
    );
};

export default ArtifactDisplay;

import { GoogleGenAI, Type } from "@google/genai";
import { ArtifactType, GeneratedArtifact } from '../types';

const API_KEY = process.env.API_KEY;
if (!API_KEY) {
    throw new Error("API_KEY environment variable not set");
}

const ai = new GoogleGenAI({ apiKey: API_KEY });

const safeParseJson = (jsonString: string): any => {
    // Attempt to find JSON within markdown code fences
    const match = jsonString.match(/```(json)?\s*([\s\S]*?)\s*```/);
    let textToParse = jsonString.trim();

    if (match && match[2]) {
        textToParse = match[2];
    } else {
        // Fallback for cases where there are no code fences, but maybe leading/trailing text
        const firstBrace = textToParse.indexOf('{');
        const lastBrace = textToParse.lastIndexOf('}');
        if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
            textToParse = textToParse.substring(firstBrace, lastBrace + 1);
        }
    }

    try {
        let parsed = JSON.parse(textToParse);
        // Handle cases where the model returns a stringified JSON object
        if (typeof parsed === 'string') {
            parsed = JSON.parse(parsed);
        }
        return parsed;
    } catch (error) {
        console.error("Failed to parse JSON:", textToParse);
        throw new Error("Received invalid JSON from the model.");
    }
};

export const suggestPersonasFromContext = async (context: string): Promise<string[]> => {
    const prompt = `Atue como um UX Researcher Sênior. Analise o contexto do projeto fornecido abaixo e identifique de 1 a 3 personas (papéis, profissões ou arquétipos de usuários) que são mais críticas para este projeto.

Contexto do Projeto:
${context}

Retorne APENAS um array JSON de strings contendo os nomes dessas personas.
Exemplo de saída: ["Estudante Universitário", "Professor de Ensino Médio"]`;

    try {
        const response = await ai.models.generateContent({
            model: "gemini-2.5-flash",
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.ARRAY,
                    items: { type: Type.STRING }
                }
            }
        });

        const parsed = safeParseJson(response.text);
        if (Array.isArray(parsed)) {
            return parsed;
        }
        return [];
    } catch (error) {
        console.error("Error suggesting personas:", error);
        return [];
    }
};

