const getUserFlows = async (context: string): Promise<GeneratedArtifact> => {
    const prompt = `Atue como um Arquiteto de Informação. Crie um fluxograma (User Flow) para a jornada principal do usuário descrita no contexto.

A resposta DEVE conter APENAS o código para um diagrama Mermaid do tipo 'graph TD'.

Regras para o diagrama:
- Use nós de decisão (losangos) onde houver escolhas (Sim/Não, Sucesso/Erro).
- Nomeie claramente as ações do usuário e as respostas do sistema.
- Comece com um nó de "Início" e termine com "Fim" ou o objetivo alcançado.
- Mantenha o fluxo lógico e legível.

Coloque o código Mermaid dentro de um bloco de código markdown.

Contexto:
${context}`;
    const response = await ai.models.generateContent({
        model: "gemini-2.5-pro",
        contents: prompt
    });

    const rawText = response.text;
    const match = rawText.match(/```(mermaid)?\s*([\s\S]*?)\s*```/);
    const mermaidCode = match && match[2] ? match[2] : rawText;

    return { text: mermaidCode.trim(), isMermaid: true };
};

const getUIScreens = async (context: string): Promise<GeneratedArtifact> => {
    const uiPrompt = `Atue como um Diretor de Arte de UI Design. Sua tarefa é escrever um prompt de geração de imagem textual altamente detalhado para criar uma tela de interface de alta fidelidade.

Considere as personas, o fluxo e os requisitos.
A resposta DEVE ser um objeto JSON com o campo "imagePrompt".

O "imagePrompt" deve descrever a tela visualmente para um modelo de IA generativa (como Imagen ou Midjourney):
- Descreva o tipo de tela (ex: Dashboard, Login, Feed, Detalhe de Produto).
- Defina o estilo visual (ex: Neomorfismo, Material Design, Minimalista, Dark Mode, Cores vibrantes).
- Descreva elementos específicos: Tipografia (Sans-serif, bold headers), Botões (arredondados, gradiente), Ícones (outline, filled).
- Descreva o conteúdo fictício visível para tornar a tela realista.

Contexto do Projeto: ${context}`;

    let uiData;
    const maxRetries = 2;

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
        try {
            const uiResponse = await ai.models.generateContent({
                model: "gemini-2.5-pro",
                contents: uiPrompt,
                config: {
                  responseMimeType: "application/json",
                  responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                      imagePrompt: { type: Type.STRING },
                    }
                  }
                }
            });

            const parsedData = safeParseJson(uiResponse.text);

            if (parsedData && typeof parsedData.imagePrompt === 'string' && parsedData.imagePrompt.trim()) {
                uiData = parsedData;
                break; // Success
            } else {
                console.warn(`Attempt ${attempt} failed: Invalid UI screen data.`, parsedData);
            }
        } catch (error) {
            console.error(`Attempt ${attempt} failed with error:`, error);
        }

        if (attempt < maxRetries) {
            console.log(`Retrying UI screen generation... (${attempt}/${maxRetries})`);
        }
    }

    if (!uiData) {
        console.error("Failed to generate valid UI screen data after all retries.");
        throw new Error("A resposta do modelo para a tela de UI veio incompleta, mesmo após tentar novamente.");
    }

    const finalImagePrompt = `Mobile app UI screen design, high fidelity, HQ, 4k. ${uiData.imagePrompt}`;

    const imageResponse = await ai.models.generateImages({
        model: 'imagen-4.0-generate-001',
        prompt: finalImagePrompt,
        config: {
          numberOfImages: 1,
          aspectRatio: "9:16",
        }
    });

    const base64Image = imageResponse.generatedImages[0].image.imageBytes;
    const imageUrl = `data:image/png;base64,${base64Image}`;

    return { text: "Aqui está uma proposta de UI para a tela solicitada, baseada em todo o contexto do projeto.", imageUrl };
};

export const generateArtifact = async (artifactType: ArtifactType, context: string): Promise<GeneratedArtifact> => {
    switch (artifactType) {
        case ArtifactType.Observation:
            return getObservationSummary(context);
        case ArtifactType.InterviewQuestions:
            return getInterviewQuestions(context);
        case ArtifactType.SummarizeInterview:
            return getInterviewSummary(context);
        case ArtifactType.Personas:
            return getPersona(context);
        case ArtifactType.AgentModel:
            return getAgentModel(context);
        case ArtifactType.EmpathyMap:
            return getEmpathyMap(context);
        case ArtifactType.FunctionalRequirements:
            return getFunctionalRequirements(context);
        case ArtifactType.UserFlows:
            return getUserFlows(context);
        case ArtifactType.UIScreens:
            return getUIScreens(context);
        default:
            throw new Error('Tipo de artefato desconhecido');
    }
};

import React, { useState } from 'react';
import { ArtifactType } from '../types';

interface InputFormProps {
    artifactType: ArtifactType;
    onSubmit: (context: string) => void;
    isLoading: boolean;
}

const placeholders: { [key in ArtifactType]: string } = {
    [ArtifactType.Observation]: 'Cole aqui suas anotações ou transcrições de observações...',
    [ArtifactType.InterviewQuestions]: 'Descreva o problema ou o contexto para o qual você precisa de perguntas de entrevista...',
    [ArtifactType.SummarizeInterview]: 'Cole aqui a transcrição completa da entrevista para ser resumida...',
    [ArtifactType.Personas]: 'Forneça o máximo de contexto sobre seu usuário-alvo: dados demográficos, comportamentos, necessidades, etc.',
    [ArtifactType.AgentModel]: 'Descreva os papéis e atores do sistema para gerar o Modelo de Agentes CommonKADS...',
    [ArtifactType.EmpathyMap]: 'Descreva a situação e o usuário para o qual o mapa de empatia será criado...',
    [ArtifactType.FunctionalRequirements]: 'Descreva o problema ou a funcionalidade para a qual deseja gerar os requisitos...',
    [ArtifactType.UserFlows]: 'Descreva a tarefa ou funcionalidade para a qual o fluxo de usuário será desenhado...',
    [ArtifactType.UIScreens]: 'Descreva em detalhes a tela que você quer gerar. Inclua funcionalidades, elementos e o objetivo da tela.',
};

const InputForm: React.FC<InputFormProps> = ({ artifactType, onSubmit, isLoading }) => {
    const [text, setText] = useState('');
    const [fileContent, setFileContent] = useState('');
    const [fileName, setFileName] = useState('');

    const handleFileChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        setFileName(file.name);
        const reader = new FileReader();
        reader.onload = (event) => {
            const content = event.target?.result as string;
            setFileContent(content);
        };
        reader.readAsText(file);
    };

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        if (!text && !fileContent) return;
        const combinedContext = `${text}\n\n${fileContent ? `--- Conteúdo do arquivo: ${fileName} ---\n${fileContent}` : ''}`;
        onSubmit(combinedContext.trim());
    };

    const canUploadFile = artifactType === ArtifactType.Observation || artifactType === ArtifactType.SummarizeInterview;

    return (
        <form onSubmit={handleSubmit} className="space-y-4">
            <div>
                <label htmlFor="context-input" className="block text-sm font-medium text-gray-400 mb-2">
                    Forneça o contexto necessário:
                </label>
                <textarea
                    id="context-input"
                    value={text}
                    onChange={(e) => setText(e.target.value)}
                    placeholder={placeholders[artifactType]}
                    rows={8}
                    className="w-full p-3 bg-zinc-900 border border-zinc-700 rounded-md focus:ring-2 focus:ring-orange-500 focus:border-orange-500 transition text-[#EFEFEF]"
                    disabled={isLoading}
                />
            </div>

            {canUploadFile && (
                 <div>
                    <label htmlFor="file-upload" className="block text-sm font-medium text-gray-400 mb-2">
                        Ou envie um arquivo de transcrição (.txt):
                    </label>
                    <input 
                        type="file" 
                        id="file-upload"
                        onChange={handleFileChange} 
                        accept=".txt,text/plain"
                        className="block w-full text-sm text-gray-400 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-orange-600 file:text-white hover:file:bg-orange-700 cursor-pointer"
                        disabled={isLoading}
                    />
                    {fileName && <p className="text-xs text-gray-500 mt-1">Arquivo carregado: {fileName}</p>}
                </div>
            )}

            <button
                type="submit"
                disabled={isLoading || (!text && !fileContent)}
                className="w-full flex justify-center py-2 px-4 border border-transparent rounded-md shadow-sm text-sm font-medium text-white bg-orange-600 hover:bg-orange-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-orange-500 disabled:bg-zinc-700 disabled:text-gray-500 disabled:cursor-not-allowed"
            >
                {isLoading ? 'Gerando...' : 'Gerar Artefato'}
            </button>
        </form>
    );
};

export default InputForm;

