import React, { useEffect, useRef } from 'react';
import { GeneratedArtifact } from '../types';

declare global {
    interface Window {
        mermaid?: {
            run: (options: { nodes: Array<Element> }) => void;
        }
    }
}

interface ArtifactDisplayProps {
    artifact: GeneratedArtifact;
}

const ArtifactDisplay: React.FC<ArtifactDisplayProps> = ({ artifact }) => {
    const isUIScreen = artifact.imageUrl && artifact.text.includes("proposta de UI");
    const mermaidRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (artifact.isMermaid && mermaidRef.current && window.mermaid) {
            const mermaidElement = mermaidRef.current.querySelector('.mermaid');
            if (mermaidElement) {
                // The artifact.text from the service is already clean Mermaid code.
                // We update the content and ensure Mermaid re-processes it.
                mermaidElement.innerHTML = artifact.text;
                mermaidElement.removeAttribute('data-processed');
                window.mermaid.run({ nodes: [mermaidElement as HTMLElement] });
            }
        }
    }, [artifact]);

    // Simple markdown parser to handle embedded images like ![Alt](data:...)
    const renderContentWithImages = (text: string) => {
        // Split text by markdown image syntax: ![Alt](Url)
        const parts = text.split(/!\[(.*?)\]\((data:image\/.*?;base64,.*?)\)/g);
        const elements: React.ReactNode[] = [];

        for (let i = 0; i < parts.length; i++) {
            // Even indices are text, odd indices are alt text and url pairs (due to regex grouping)
            if (i % 3 === 0) {
                if (parts[i]) {
                    elements.push(<span key={i}>{parts[i]}</span>);
                }
            } else if (i % 3 === 1) {
                const alt = parts[i];
                const src = parts[i + 1];
                elements.push(
                    <div key={i} className="my-4 flex justify-center">
                        <img 
                            src={src} 
                            alt={alt} 
                            className="rounded-lg shadow-lg border-2 border-zinc-700 max-w-full h-auto max-h-96 object-cover" 
                        />
                    </div>
                );
                i++; // Skip the next part (src) as we consumed it
            }
        }
        return elements;
    };

    if (artifact.isMermaid) {
        return (
            <div ref={mermaidRef}>
                <pre className="mermaid language-mermaid bg-zinc-900/50 p-4 rounded-lg text-center border border-zinc-700">
                    {/* The useEffect will populate this */}
                </pre>
            </div>
        );
    }

    return (
        <div className="space-y-4">
            {artifact.imageUrl && (
                <div className={`flex justify-center ${isUIScreen ? 'w-full' : ''}`}>
                    <img
                        src={artifact.imageUrl}
                        alt="Artefato Gerado"
                        className={`rounded-lg shadow-lg object-cover border-4 border-zinc-700 ${isUIScreen ? 'w-full max-w-sm' : 'w-64 h-64'}`}
                    />
                </div>
            )}
            <div className="prose prose-invert prose-sm sm:prose-base max-w-none bg-zinc-900/50 p-4 rounded-lg border border-zinc-700">
                <div className="whitespace-pre-wrap font-sans text-[#EFEFEF]">
                    {renderContentWithImages(artifact.text)}
                </div>
            </div>
        </div>
    );
};

export default ArtifactDisplay;

import { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType, ImageRun } from "docx";
import { jsPDF } from "jspdf";

export const generateAndDownloadDocx = async (title: string, subtitle: string, content: string) => {
    const lines = content.split('\n');
    const docChildren: (Paragraph)[] = [];

    // Title
    docChildren.push(
        new Paragraph({
            text: title,
            heading: HeadingLevel.TITLE,
            alignment: AlignmentType.CENTER,
            spacing: { after: 300 },
        })
    );

    // Subtitle
    docChildren.push(
        new Paragraph({
            text: subtitle,
            heading: HeadingLevel.HEADING_2,
            alignment: AlignmentType.CENTER,
            spacing: { after: 300 },
        })
    );

    // Process Content
    // Regex to detect embedded images: ![Alt](data:image/png;base64,...)
    const imageRegex = /^!\[(.*?)\]\((data:image\/.*?;base64,.*?)\)$/;

    for (const line of lines) {
        const trimmed = line.trim();
        if (!trimmed) {
            docChildren.push(new Paragraph({ text: "" })); // Empty line
            continue;
        }

        const imageMatch = trimmed.match(imageRegex);

        if (imageMatch) {
            try {
                const base64Data = imageMatch[2].split(',')[1];
                const imageBuffer = Uint8Array.from(atob(base64Data), c => c.charCodeAt(0));

                docChildren.push(new Paragraph({
                    children: [
                        new ImageRun({
                            data: imageBuffer,
                            transformation: {
                                width: 300,
                                height: 300,
                            },
                            type: "png" // Assuming PNG based on service generation
                        })
                    ],
                    alignment: AlignmentType.CENTER,
                    spacing: { before: 200, after: 200 }
                }));
            } catch (e) {
                console.error("Error embedding image in Docx", e);
            }
            continue;
        }

        if (trimmed.startsWith('### ')) {
            docChildren.push(new Paragraph({
                text: trimmed.replace('### ', ''),
                heading: HeadingLevel.HEADING_3,
                spacing: { before: 200, after: 100 }
            }));
        } else if (trimmed.startsWith('## ')) {
            docChildren.push(new Paragraph({
                text: trimmed.replace('## ', ''),
                heading: HeadingLevel.HEADING_2,
                spacing: { before: 240, after: 120 }
            }));
        } else if (trimmed.startsWith('# ')) {
            docChildren.push(new Paragraph({
                text: trimmed.replace('# ', ''),
                heading: HeadingLevel.HEADING_1,
                spacing: { before: 280, after: 140 }
            }));
        } else if (trimmed.startsWith('- ') || trimmed.startsWith('* ')) {
             // Handle bold in list items
             const textContent = trimmed.substring(2);
             const parts = parseBoldText(textContent);

             docChildren.push(new Paragraph({
                children: parts,
                bullet: { level: 0 }
            }));
        } else {
            // Standard paragraph with bold parsing
            const parts = parseBoldText(trimmed);
            docChildren.push(new Paragraph({
                children: parts,
                spacing: { after: 120 }
            }));
        }
    }

    const doc = new Document({
        sections: [{
            properties: {},
            children: docChildren,
        }],
    });

    const blob = await Packer.toBlob(doc);
    saveBlob(blob, `${subtitle.replace(/\s+/g, '_')}.docx`);
};

export const generateAndDownloadPdf = (title: string, subtitle: string, content: string) => {
    const doc = new jsPDF();
    const pageWidth = doc.internal.pageSize.getWidth();
    const pageHeight = doc.internal.pageSize.getHeight();
    const margin = 15;
    const maxLineWidth = pageWidth - (margin * 2);
    let yPos = 20;

    // Title
    doc.setFontSize(18);
    doc.setFont("helvetica", "bold");
    doc.text(title, pageWidth / 2, yPos, { align: "center" });
    yPos += 10;

    // Subtitle
    doc.setFontSize(14);
    doc.setFont("helvetica", "normal");
    doc.text(subtitle, pageWidth / 2, yPos, { align: "center" });
    yPos += 15;

    doc.setFontSize(11);

    const lines = content.split('\n');

    // Regex to detect embedded images
    const imageRegex = /^!\[(.*?)\]\((data:image\/.*?;base64,.*?)\)$/;

    lines.forEach(line => {
        // Simple pagination check
        if (yPos > pageHeight - margin) {
            doc.addPage();
            yPos = 20;
        }

        const trimmed = line.trim();
        if (!trimmed) {
            yPos += 5;
            return;
        }

        const imageMatch = trimmed.match(imageRegex);
        if (imageMatch) {
            try {
                const base64Data = imageMatch[2];
                // Check if image fits on page, if not, add page
                const imgHeight = 80; // Fixed height for PDF
                if (yPos + imgHeight > pageHeight - margin) {
                    doc.addPage();
                    yPos = 20;
                }

                // Center image
                const imgWidth = 80; // Aspect ratio assumed square for personas
                const xPos = (pageWidth - imgWidth) / 2;

                doc.addImage(base64Data, 'PNG', xPos, yPos, imgWidth, imgHeight);
                yPos += imgHeight + 10;
            } catch (e) {
                console.error("Error adding image to PDF", e);
            }
            return;
        }

        // Clean markdown symbols for PDF readability (Simplified)
        let textToPrint = trimmed;
        let isHeading = false;

        if (trimmed.startsWith('#')) {
            isHeading = true;
            textToPrint = trimmed.replace(/^#+\s/, '');
        } else if (trimmed.startsWith('- ') || trimmed.startsWith('* ')) {
            textToPrint = '• ' + trimmed.substring(2);
        }

        // Remove bold markers for PDF (parsing bold mid-sentence in jsPDF is complex)
        textToPrint = textToPrint.replace(/\*\*/g, '');

        if (isHeading) {
            doc.setFont("helvetica", "bold");
            doc.setFontSize(12);
            yPos += 5;
        } else {
            doc.setFont("helvetica", "normal");
            doc.setFontSize(11);
        }

        const splitText = doc.splitTextToSize(textToPrint, maxLineWidth);
        doc.text(splitText, margin, yPos);
        yPos += (splitText.length * 5) + 2; 

        if (isHeading) yPos += 3;
    });

    doc.save(`${subtitle.replace(/\s+/g, '_')}.pdf`);
};

// Helper to split string into TextRuns for DOCX bold handling
const parseBoldText = (text: string): TextRun[] => {
    const parts: TextRun[] = [];
    // Split by **text**
    const regex = /\*\*(.*?)\*\*/g;
    let lastIndex = 0;
    let match;

    while ((match = regex.exec(text)) !== null) {
        // Text before bold
        if (match.index > lastIndex) {
            parts.push(new TextRun(text.substring(lastIndex, match.index)));
        }
        // Bold text
        parts.push(new TextRun({
            text: match[1],
            bold: true,
        }));
        lastIndex = regex.lastIndex;
    }

    // Remaining text
    if (lastIndex < text.length) {
        parts.push(new TextRun(text.substring(lastIndex)));
    }

    return parts;
};

const saveBlob = (blob: Blob, fileName: string) => {
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement("a");
    document.body.appendChild(a);
    a.style.display = "none";
    a.href = url;
    a.download = fileName;
    a.click();
    window.URL.revokeObjectURL(url);
    document.body.removeChild(a);
};

import React, { useState, useCallback, useRef, useEffect } from 'react';
import { ArtifactType, Message, GeneratedArtifact } from './types';
import { generateArtifact, suggestPersonasFromContext } from './services/geminiService';
import OptionSelector from './components/OptionSelector';
import InputForm from './components/InputForm';
import ArtifactDisplay from './components/ArtifactDisplay';
import LoadingSpinner from './components/LoadingSpinner';
import ChatMessage from './components/ChatMessage';
import AdditionalInfoForm from './components/AdditionalInfoForm';
import DownloadOptions from './components/DownloadOptions';

const App: React.FC = () => {
    const [messages, setMessages] = useState<Message[]>([]);
    const [isLoading, setIsLoading] = useState<boolean>(false);
    const [projectContext, setProjectContext] = useState<string>('');
    const [completedArtifacts, setCompletedArtifacts] = useState<ArtifactType[]>([]);
    const [currentArtifactType, setCurrentArtifactType] = useState<ArtifactType | null>(null);
    const messagesEndRef = useRef<HTMLDivElement>(null);
    const handleOptionSelectRef = useRef<((type: ArtifactType) => void) | null>(null);

    // Refs for special flows (Agent Model and MO Tables)
    const handleAgentModelTriggerRef = useRef<() => void>(null);
    const handleMOTablesTriggerRef = useRef<() => void>(null);
    const handleMainMenuTriggerRef = useRef<() => void>(null);

    // Ref to hold the latest state to avoid stale closures in callbacks
    const stateRef = useRef({ projectContext, completedArtifacts, currentArtifactType });
    useEffect(() => {
        stateRef.current = { projectContext, completedArtifacts, currentArtifactType };
    });

    const addMessage = useCallback((sender: 'bot' | 'user', content: React.ReactNode): string => {
        const id = `${Date.now()}-${Math.random()}`;
        setMessages(prev => [...prev, { id, sender, content }]);
        return id;
    }, []);

    const updateMessage = useCallback((id: string, content: React.ReactNode) => {
        setMessages(prev => prev.map(m => m.id === id ? { ...m, content } : m));
    }, []);

    const showMainMenu = useCallback((customText?: string) => {
        addMessage('bot', 
            <>
                <p className="mb-4">{customText || "O que você gostaria de fazer agora?"}</p>
                <OptionSelector 
                    onSelect={(type) => handleOptionSelectRef.current?.(type)} 
                    completedArtifacts={stateRef.current.completedArtifacts} 
                />
            </>
        );
    }, [addMessage]);

    const initialBotMessage = useCallback(() => {
         addMessage('bot', 
            <>
                <p className="mb-4">Olá! Sou seu assistente de UX. Como posso ajudar a iniciar seu projeto?</p>
                <OptionSelector onSelect={(type) => handleOptionSelectRef.current?.(type)} completedArtifacts={[]} />
            </>
        );
    }, [addMessage]);

    useEffect(() => {
       initialBotMessage();
        // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [initialBotMessage]);

    useEffect(() => {
        messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    }, [messages]);

    const handleGeneration = useCallback(async (artifactType: ArtifactType, context: string, isPrimaryInput: boolean) => {
        setIsLoading(true);
        const loadingMessageId = addMessage('bot', <LoadingSpinner />);
        try {
            const result: GeneratedArtifact = await generateArtifact(artifactType, context);

            // CRITICAL FIX: Remove Base64 images from the context text before saving to state.
            // This prevents the "token limit exceeded" error when sending history back to Gemini.
            // We replace the image syntax ![Alt](data:...) with a placeholder [Imagem: Alt].
            const textWithoutImages = result.text.replace(/!\[(.*?)\]\(data:image\/.*?;base64,.*?\)/g, '\n> [Imagem Gerada: $1]\n');

            if (isPrimaryInput) {
                 setProjectContext(`## ${artifactType}\n\n${textWithoutImages}`);
            } else {
                 setProjectContext(prev => `${prev}\n\n---\n\n## ${artifactType}\n\n${textWithoutImages}`);
            }

            const newCompletedArtifacts = [...stateRef.current.completedArtifacts, artifactType];
            setCompletedArtifacts(newCompletedArtifacts);

            updateMessage(loadingMessageId, <ArtifactDisplay artifact={result} />);

            // Add Download Options
            addMessage('bot', 
                <>
                    <p className="text-sm text-gray-400 mb-2">Deseja salvar este artefato?</p>
                    <DownloadOptions artifactName={artifactType} content={result.text} />
                </>
            );

            // Flow Control based on Artifact Type
            if (artifactType === ArtifactType.Personas) {
                // Fluxo específico para sugerir o Modelo de Agentes (CommonKADS)
                addMessage('bot', 
                    <div className="flex flex-col gap-4 bg-zinc-800/50 p-4 rounded-lg border border-zinc-700 mt-2">
                        <div>
                            <p className="mb-2">Personas geradas com sucesso!</p>
                            <p className="text-sm text-gray-300 mb-4">
                                Uma prática recomendada é estruturar esses papéis usando o <strong>Modelo de Agentes (CommonKADS)</strong> para definir responsabilidades, comunicação e restrições.
                            </p>
                            <p className="font-semibold text-orange-400">Deseja gerar o Modelo de Agentes para as personas acima?</p>
                        </div>
                        <div className="flex flex-wrap gap-3">
                            <button 
                                onClick={() => handleAgentModelTriggerRef.current?.()}
                                className="px-4 py-2 bg-orange-600 text-white rounded-md hover:bg-orange-700 transition flex-1 sm:flex-none shadow-md font-medium"
                            >
                                Sim, gerar Modelo de Agentes
                            </button>
                            <button 
                                onClick={() => handleMainMenuTriggerRef.current?.()}
                                className="px-4 py-2 bg-zinc-700 text-white rounded-md hover:bg-zinc-600 transition flex-1 sm:flex-none border border-zinc-600"
                            >
                                Não, ver outras opções
                            </button>
                        </div>
                    </div>
                );
            } else if (artifactType === ArtifactType.SummarizeInterview) {
                // Fluxo específico para sugerir Tabelas MO (CommonKADS)
                addMessage('bot', 
                    <div className="flex flex-col gap-4 bg-zinc-800/50 p-4 rounded-lg border border-zinc-700 mt-2">
                        <div>
                            <p className="mb-2">Resumo da entrevista concluído!</p>
                            <p className="text-sm text-gray-300 mb-4">
                                Com base nos problemas identificados, podemos criar as <strong>Tabelas MO1 (Contexto)</strong> e <strong>MO5 (Viabilidade)</strong> do Modelo Organizacional (CommonKADS).
                            </p>
                            <p className="font-semibold text-orange-400">Deseja criar as Tabelas MO agora?</p>
                        </div>
                        <div className="flex flex-wrap gap-3">
                            <button 
                                onClick={() => handleMOTablesTriggerRef.current?.()}
                                className="px-4 py-2 bg-orange-600 text-white rounded-md hover:bg-orange-700 transition flex-1 sm:flex-none shadow-md font-medium"
                            >
                                Sim, criar Tabelas MO
                            </button>
                            <button 
                                onClick={() => handleMainMenuTriggerRef.current?.()}
                                className="px-4 py-2 bg-zinc-700 text-white rounded-md hover:bg-zinc-600 transition flex-1 sm:flex-none border border-zinc-600"
                            >
                                Não, ver outras opções
                            </button>
                        </div>
                    </div>
                );
            } else {
                // Fluxo padrão
                addMessage('bot', 
                    <>
                        <p className="mb-4">Excelente! O que você gostaria de fazer agora?</p>
                        <OptionSelector onSelect={(type) => handleOptionSelectRef.current?.(type)} completedArtifacts={newCompletedArtifacts} />
                    </>
                );
            }

        } catch (error) {
            console.error('Error generating artifact:', error);
            updateMessage(loadingMessageId, <p className="text-red-400">Desculpe, ocorreu um erro ao gerar o artefato. Isso pode ocorrer se o contexto estiver muito longo ou se houver instabilidade na API. Tente simplificar a solicitação.</p>);
            showMainMenu("Ocorreu um erro. O que você gostaria de fazer agora?");
        } finally {
            setIsLoading(false);
        }
    }, [addMessage, updateMessage, showMainMenu]);

    // Implementação dos handlers via refs para evitar dependências circulares/stale closures nos botões renderizados
    useEffect(() => {
        handleAgentModelTriggerRef.current = () => {
            addMessage('user', "Sim, gerar Modelo de Agentes");
            handleGeneration(ArtifactType.AgentModel, stateRef.current.projectContext, false);
        };

        handleMOTablesTriggerRef.current = () => {
            addMessage('user', "Sim, criar as Tabelas MO");
            handleGeneration(ArtifactType.MOTables, stateRef.current.projectContext, false);
        };

        handleMainMenuTriggerRef.current = () => {
             addMessage('user', "Não, obrigado.");
             showMainMenu("Tudo bem! O que mais você deseja criar?");
        };
    }, [addMessage, handleGeneration, showMainMenu]);

    const handleInputSubmit = useCallback((context: string) => {
        const artifactType = stateRef.current.currentArtifactType;
        if (!artifactType) return;

        const contextToShow = context.length > 300 ? `${context.substring(0, 300)}...` : context;
        addMessage('user', <pre className="whitespace-pre-wrap font-sans">{contextToShow}</pre>);

        handleGeneration(artifactType, context, true);
    }, [addMessage, handleGeneration]);

    const handleAdditionalInfoSubmit = useCallback((additionalContext: string) => {
        const artifactType = stateRef.current.currentArtifactType;
        if (!artifactType) return;

        if(additionalContext) {
            const contextToShow = additionalContext.length > 300 ? `${additionalContext.substring(0, 300)}...` : additionalContext;
            addMessage('user', <pre className="whitespace-pre-wrap font-sans">{contextToShow}</pre>);
        } else {
            addMessage('user', "(Nenhuma informação adicional)");
        }

        const fullContext = `${stateRef.current.projectContext}\n\n--- INFORMAÇÕES ADICIONAIS DO USUÁRIO ---\n${additionalContext}`;
        handleGeneration(artifactType, fullContext.trim(), false);

    }, [addMessage, handleGeneration]);

    const handleOptionSelect = useCallback(async (type: ArtifactType) => {
        setCurrentArtifactType(type);
        addMessage('user', `Eu escolho: ${type}`);

        const { projectContext } = stateRef.current;

        // Special handling for Personas when context exists
        if (type === ArtifactType.Personas && projectContext) {
            setIsLoading(true);
            const loadingId = addMessage('bot', <LoadingSpinner />);

            try {
                // Analyze context to find suggested personas
                const suggestions = await suggestPersonasFromContext(projectContext);

                let suggestionMessage = "";
                if (suggestions.length > 0) {
                    const names = suggestions.join(', ');
                    suggestionMessage = `Com base no contexto anterior, identifiquei que devem ser observadas as necessidades de ${suggestions.length > 1 ? 'destas personas' : 'desta persona'}: **${names}**.`;
                } else {
                    suggestionMessage = "Analisei o contexto, mas não identifiquei papéis explícitos, porém podemos criar personas baseadas nos dados gerais.";
                }

                updateMessage(loadingId, <p>{suggestionMessage}</p>);

                // Define a specific submit handler for this step that includes the suggestions
                const handlePersonaSubmit = (additionalInput: string) => {
                    if(additionalInput) {
                        const contextToShow = additionalInput.length > 300 ? `${additionalInput.substring(0, 300)}...` : additionalInput;
                        addMessage('user', <pre className="whitespace-pre-wrap font-sans">{contextToShow}</pre>);
                    } else {
                        addMessage('user', "(Sem adicionar mais personas)");
                    }

                    const combinedContext = `
                        ${stateRef.current.projectContext}

                        --- DIRECIONAMENTO DE PERSONAS ---
                        Personas Sugeridas pelo Sistema: ${suggestions.join(', ')}
                        Solicitação Adicional do Usuário: ${additionalInput}
                    `.trim();

                    handleGeneration(ArtifactType.Personas, combinedContext, false);
                };

                // Show the form asking if user wants to add more
                addMessage('bot', 
                    <AdditionalInfoForm 
                        artifactType={type} 
                        onSubmit={handlePersonaSubmit} 
                        isLoading={false}
                        customLabel="Deseja incluir mais alguma persona para geração? Se sim, digite abaixo (ex: 'Também inclua um Gerente de Loja'). Caso contrário, apenas clique em Gerar."
                    />
                );

            } catch (error) {
                console.error("Error suggesting personas:", error);
                // Fallback to normal flow if suggestion fails
                 addMessage('bot', <AdditionalInfoForm artifactType={type} onSubmit={handleAdditionalInfoSubmit} isLoading={false} />);
            } finally {
                setIsLoading(false);
            }
            return;
        }

        // Standard flow for other artifacts or empty context
        if (!projectContext) {
             addMessage('bot', <InputForm artifactType={type} onSubmit={handleInputSubmit} isLoading={isLoading} />);
        } else {
            addMessage('bot', <AdditionalInfoForm artifactType={type} onSubmit={handleAdditionalInfoSubmit} isLoading={isLoading} />);
        }
    }, [isLoading, addMessage, handleInputSubmit, handleAdditionalInfoSubmit, handleGeneration, updateMessage]);

    useEffect(() => {
        handleOptionSelectRef.current = handleOptionSelect;
    }, [handleOptionSelect]);

    return (
        <div className="flex flex-col h-screen bg-zinc-950 text-[#EFEFEF] font-sans">
            <header className="bg-zinc-900/80 backdrop-blur-sm p-4 border-b border-zinc-800 shadow-lg fixed top-0 left-0 right-0 z-10">
                <h1 className="text-xl md:text-2xl font-bold text-center bg-clip-text text-transparent bg-gradient-to-r from-orange-500 to-amber-500">
                    Gerador de Artefatos de UX
                </h1>
            </header>
            <main className="flex-1 overflow-y-auto p-4 pt-24 pb-8">
                <div className="max-w-3xl mx-auto space-y-6">
                    {messages.map((msg) => (
                        <ChatMessage key={msg.id} sender={msg.sender}>
                            {msg.content}
                        </ChatMessage>
                    ))}
                    <div ref={messagesEndRef} />
                </div>
            </main>
        </div>
    );
};

