import React, { useEffect, useRef } from 'react';
import { GeneratedArtifact } from '../types';

declare global {
    interface Window {
        mermaid?: {
            run: (options: { nodes: Array<Element> }) => void;
        }
    }
}

interface ArtifactDisplayProps {
    artifact: GeneratedArtifact;
}

const ArtifactDisplay: React.FC<ArtifactDisplayProps> = ({ artifact }) => {
    const isUIScreen = artifact.imageUrl && artifact.text.includes("proposta de UI");
    const mermaidRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
        if (artifact.isMermaid && mermaidRef.current && window.mermaid) {
            const mermaidElement = mermaidRef.current.querySelector('.mermaid');
            if (mermaidElement) {
                // The artifact.text from the service is already clean Mermaid code.
                // We update the content and ensure Mermaid re-processes it.
                mermaidElement.innerHTML = artifact.text;
                mermaidElement.removeAttribute('data-processed');
                window.mermaid.run({ nodes: [mermaidElement as HTMLElement] });
            }
        }
    }, [artifact]);

    // Simple markdown parser to handle embedded images like ![Alt](data:...)
    const renderContentWithImages = (text: string) => {
        // Split text by markdown image syntax: ![Alt](Url)
        const parts = text.split(/!\[(.*?)\]\((data:image\/.*?;base64,.*?)\)/g);
        const elements: React.ReactNode[] = [];

        for (let i = 0; i < parts.length; i++) {
            // Even indices are text, odd indices are alt text and url pairs (due to regex grouping)
            if (i % 3 === 0) {
                if (parts[i]) {
                    elements.push(<span key={i}>{parts[i]}</span>);
                }
            } else if (i % 3 === 1) {
                const alt = parts[i];
                const src = parts[i + 1];
                elements.push(
                    <div key={i} className="my-6 flex justify-center group">
                        <div className="relative rounded-lg overflow-hidden shadow-2xl transition-transform duration-300 group-hover:scale-[1.01]">
                             <div className="absolute inset-0 border-2 border-white/10 rounded-lg pointer-events-none z-10"></div>
                            <img 
                                src={src} 
                                alt={alt} 
                                className="max-w-full h-auto max-h-96 object-cover bg-zinc-900" 
                            />
                        </div>
                    </div>
                );
                i++; // Skip the next part (src) as we consumed it
            }
        }
        return elements;
    };

    if (artifact.isMermaid) {
        return (
            <div ref={mermaidRef}>
                <pre className="mermaid language-mermaid bg-zinc-900/60 backdrop-blur-md p-6 rounded-xl text-center border border-white/10 shadow-inner">
                    {/* The useEffect will populate this */}
                </pre>
            </div>
        );
    }

    return (
        <div className="space-y-6">
            {artifact.imageUrl && (
                <div className={`flex justify-center ${isUIScreen ? 'w-full' : ''}`}>
                    <div className={`relative rounded-xl overflow-hidden shadow-2xl border-4 border-zinc-800/50 ${isUIScreen ? 'w-full max-w-sm' : 'w-64 h-64'}`}>
                        <img
                            src={artifact.imageUrl}
                            alt="Artefato Gerado"
                            className="w-full h-full object-cover"
                        />
                         <div className="absolute inset-0 shadow-[inset_0_0_20px_rgba(0,0,0,0.5)] pointer-events-none"></div>
                    </div>
                </div>
            )}
            <div className="prose prose-invert prose-sm sm:prose-base max-w-none bg-zinc-950/40 backdrop-blur-sm p-6 rounded-2xl border border-white/5 shadow-inner">
                <div className="whitespace-pre-wrap font-sans text-gray-200 leading-relaxed">
                    {renderContentWithImages(artifact.text)}
                </div>
            </div>
        </div>
    );
};

