import { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType, ImageRun } from "docx";
import { jsPDF } from "jspdf";

export const generateAndDownloadDocx = async (title: string, subtitle: string, content: string) => {
    const lines = content.split('\n');
    const docChildren: (Paragraph)[] = [];

    // Title
    docChildren.push(
        new Paragraph({
            text: title,
            heading: HeadingLevel.TITLE,
            alignment: AlignmentType.CENTER,
            spacing: { after: 300 },
        })
    );

    // Subtitle
    docChildren.push(
        new Paragraph({
            text: subtitle,
            heading: HeadingLevel.HEADING_2,
            alignment: AlignmentType.CENTER,
            spacing: { after: 300 },
        })
    );

    // Process Content
    // Regex to detect embedded images: ![Alt](data:image/png;base64,...)
    const imageRegex = /^!\[(.*?)\]\((data:image\/.*?;base64,.*?)\)$/;

    for (const line of lines) {
        const trimmed = line.trim();
        if (!trimmed) {
            docChildren.push(new Paragraph({ text: "" })); // Empty line
            continue;
        }

        const imageMatch = trimmed.match(imageRegex);

        if (imageMatch) {
            try {
                const base64Data = imageMatch[2].split(',')[1];
                const imageBuffer = Uint8Array.from(atob(base64Data), c => c.charCodeAt(0));

                docChildren.push(new Paragraph({
                    children: [
                        new ImageRun({
                            data: imageBuffer,
                            transformation: {
                                width: 300,
                                height: 300,
                            },
                            type: "png" // Assuming PNG based on service generation
                        })
                    ],
                    alignment: AlignmentType.CENTER,
                    spacing: { before: 200, after: 200 }
                }));
            } catch (e) {
                console.error("Error embedding image in Docx", e);
            }
            continue;
        }

        if (trimmed.startsWith('### ')) {
            docChildren.push(new Paragraph({
                text: trimmed.replace('### ', ''),
                heading: HeadingLevel.HEADING_3,
                spacing: { before: 200, after: 100 }
            }));
        } else if (trimmed.startsWith('## ')) {
            docChildren.push(new Paragraph({
                text: trimmed.replace('## ', ''),
                heading: HeadingLevel.HEADING_2,
                spacing: { before: 240, after: 120 }
            }));
        } else if (trimmed.startsWith('# ')) {
            docChildren.push(new Paragraph({
                text: trimmed.replace('# ', ''),
                heading: HeadingLevel.HEADING_1,
                spacing: { before: 280, after: 140 }
            }));
        } else if (trimmed.startsWith('- ') || trimmed.startsWith('* ')) {
             // Handle bold in list items
             const textContent = trimmed.substring(2);
             const parts = parseBoldText(textContent);

             docChildren.push(new Paragraph({
                children: parts,
                bullet: { level: 0 }
            }));
        } else {
            // Standard paragraph with bold parsing
            const parts = parseBoldText(trimmed);
            docChildren.push(new Paragraph({
                children: parts,
                spacing: { after: 120 }
            }));
        }
    }

    const doc = new Document({
        sections: [{
            properties: {},
            children: docChildren,
        }],
    });

    const blob = await Packer.toBlob(doc);
    saveBlob(blob, `${subtitle.replace(/\s+/g, '_')}.docx`);
};

export const generateAndDownloadPdf = (title: string, subtitle: string, content: string) => {
    const doc = new jsPDF();
    const pageWidth = doc.internal.pageSize.getWidth();
    const pageHeight = doc.internal.pageSize.getHeight();
    const margin = 15;
    const maxLineWidth = pageWidth - (margin * 2);
    let yPos = 20;

    // Title
    doc.setFontSize(18);
    doc.setFont("helvetica", "bold");
    doc.text(title, pageWidth / 2, yPos, { align: "center" });
    yPos += 10;

    // Subtitle
    doc.setFontSize(14);
    doc.setFont("helvetica", "normal");
    doc.text(subtitle, pageWidth / 2, yPos, { align: "center" });
    yPos += 15;

    doc.setFontSize(11);

    const lines = content.split('\n');

    // Regex to detect embedded images
    const imageRegex = /^!\[(.*?)\]\((data:image\/.*?;base64,.*?)\)$/;

    lines.forEach(line => {
        const trimmed = line.trim();

        // Handle empty lines simply
        if (!trimmed) {
            yPos += 5;
            // Check page break even for empty lines to avoid orphan spacing at bottom
            if (yPos > pageHeight - margin) {
                doc.addPage();
                yPos = 20;
            }
            return;
        }

        // Image Handling
        const imageMatch = trimmed.match(imageRegex);
        if (imageMatch) {
            try {
                const base64Data = imageMatch[2];
                const imgHeight = 80; // Fixed height for PDF

                // Check if image fits on page
                if (yPos + imgHeight > pageHeight - margin) {
                    doc.addPage();
                    yPos = 20;
                }

                // Center image
                const imgWidth = 80;
                const xPos = (pageWidth - imgWidth) / 2;

                doc.addImage(base64Data, 'PNG', xPos, yPos, imgWidth, imgHeight);
                yPos += imgHeight + 10;
            } catch (e) {
                console.error("Error adding image to PDF", e);
            }
            return;
        }

        // Text Formatting
        let textToPrint = trimmed;
        let isHeading = false;
        let fontSize = 11;
        let fontStyle = "normal";
        let extraSpacing = 0;

        if (trimmed.startsWith('#')) {
            isHeading = true;
            textToPrint = trimmed.replace(/^#+\s/, '');
            fontStyle = "bold";
            fontSize = 12;
            extraSpacing = 3;
        } else if (trimmed.startsWith('- ') || trimmed.startsWith('* ')) {
            textToPrint = '• ' + trimmed.substring(2);
        }

        // Remove markdown bold markers
        textToPrint = textToPrint.replace(/\*\*/g, '');

        doc.setFont("helvetica", fontStyle);
        doc.setFontSize(fontSize);

        // Split text into lines that fit the width
        const splitText = doc.splitTextToSize(textToPrint, maxLineWidth);
        const lineHeight = isHeading ? 7 : 6;

        // PAGINATION LOGIC:
        // Instead of dumping the whole block, we check if the block fits.
        // If it's a heading, we want to ensure it's not at the very bottom.

        // Calculate total height needed for this block
        const blockHeight = splitText.length * lineHeight;

        if (yPos + blockHeight > pageHeight - margin) {
            // If the block is huge (larger than a page) OR fits better on the next page
            // We have two strategies:
            // 1. If it fits on the next page entirely, move it there.
            // 2. If it's larger than a page, we must split it.

            if (blockHeight < (pageHeight - (margin * 2))) {
                // It fits on a new page, move everything
                doc.addPage();
                yPos = 20;
                doc.text(splitText, margin, yPos);
                yPos += blockHeight + 2 + extraSpacing;
            } else {
                // It's a massive paragraph (rare for bios, but possible). 
                // Print line by line to break correctly.
                splitText.forEach((textLine: string) => {
                    if (yPos + lineHeight > pageHeight - margin) {
                        doc.addPage();
                        yPos = 20;
                    }
                    doc.text(textLine, margin, yPos);
                    yPos += lineHeight;
                });
                yPos += 2 + extraSpacing;
            }
        } else {
            // Fits on current page
            doc.text(splitText, margin, yPos);
            yPos += blockHeight + 2 + extraSpacing;
        }
    });

    doc.save(`${subtitle.replace(/\s+/g, '_')}.pdf`);
};

// Helper to split string into TextRuns for DOCX bold handling
const parseBoldText = (text: string): TextRun[] => {
    const parts: TextRun[] = [];
    // Split by **text**
    const regex = /\*\*(.*?)\*\*/g;
    let lastIndex = 0;
    let match;

    while ((match = regex.exec(text)) !== null) {
        // Text before bold
        if (match.index > lastIndex) {
            parts.push(new TextRun(text.substring(lastIndex, match.index)));
        }
        // Bold text
        parts.push(new TextRun({
            text: match[1],
            bold: true,
        }));
        lastIndex = regex.lastIndex;
    }

    // Remaining text
    if (lastIndex < text.length) {
        parts.push(new TextRun(text.substring(lastIndex)));
    }

    return parts;
};

const saveBlob = (blob: Blob, fileName: string) => {
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement("a");
    document.body.appendChild(a);
    a.style.display = "none";
    a.href = url;
    a.download = fileName;
    a.click();
    window.URL.revokeObjectURL(url);
    document.body.removeChild(a);
};

