export const generateAndDownloadPdf = (title: string, subtitle: string, content: string) => {
    const doc = new jsPDF();
    const pageWidth = doc.internal.pageSize.getWidth();
    const pageHeight = doc.internal.pageSize.getHeight();
    const margin = 20; // Increased margin for cleaner look
    const maxLineWidth = pageWidth - (margin * 2);
    let yPos = 20;

    // --- Helper Functions for Theme ---

    const drawPageBackground = () => {
        // Fill Page Background
        doc.setFillColor(THEME.bg[0], THEME.bg[1], THEME.bg[2]);
        doc.rect(0, 0, pageWidth, pageHeight, 'F');

        // Draw Header Line / App Branding
        doc.setDrawColor(THEME.accent[0], THEME.accent[1], THEME.accent[2]);
        doc.setLineWidth(0.5);
        doc.line(margin, 15, pageWidth - margin, 15);

        doc.setFontSize(8);
        doc.setTextColor(THEME.accentSecondary[0], THEME.accentSecondary[1], THEME.accentSecondary[2]);
        doc.setFont("helvetica", "bold");
        doc.text("AGENTE UX", margin, 12);

        doc.setTextColor(100, 100, 100);
        doc.setFont("helvetica", "normal");
        doc.text(new Date().toLocaleDateString(), pageWidth - margin, 12, { align: "right" });
    };

    const checkPageBreak = (heightNeeded: number) => {
        if (yPos + heightNeeded > pageHeight - margin) {
            doc.addPage();
            drawPageBackground();
            yPos = 30; // Start lower on new pages
            return true;
        }
        return false;
    };

    // --- Initial Page Setup ---
    drawPageBackground();
    yPos = 30;

    // Document Title
    doc.setFontSize(22);
    doc.setTextColor(THEME.accent[0], THEME.accent[1], THEME.accent[2]);
    doc.setFont("helvetica", "bold");
    doc.text(title, pageWidth / 2, yPos, { align: "center" });
    yPos += 12;

    // Document Subtitle
    doc.setFontSize(16);
    doc.setTextColor(THEME.textBold[0], THEME.textBold[1], THEME.textBold[2]);
    doc.setFont("helvetica", "normal");
    doc.text(subtitle, pageWidth / 2, yPos, { align: "center" });
    yPos += 20;

    // Draw separator after title
    doc.setDrawColor(THEME.border[0], THEME.border[1], THEME.border[2]);
    doc.line(margin, yPos - 10, pageWidth - margin, yPos - 10);

    doc.setFontSize(11);

    const lines = content.split('\n');
    const imageRegex = /^!\[(.*?)\]\((data:image\/.*?;base64,.*?)\)$/;

    lines.forEach(line => {
        const trimmed = line.trim();

        if (!trimmed) {
            yPos += 5;
            checkPageBreak(10);
            return;
        }

        // Image Handling
        const imageMatch = trimmed.match(imageRegex);
        if (imageMatch) {
            try {
                const base64Data = imageMatch[2];
                const imgHeight = 90; 
                const imgWidth = 90;

                checkPageBreak(imgHeight + 10);

                const xPos = (pageWidth - imgWidth) / 2;

                // Draw a frame for the image
                doc.setDrawColor(THEME.border[0], THEME.border[1], THEME.border[2]);
                doc.setFillColor(THEME.cardBg[0], THEME.cardBg[1], THEME.cardBg[2]);
                doc.roundedRect(xPos - 2, yPos - 2, imgWidth + 4, imgHeight + 4, 3, 3, 'FD');

                doc.addImage(base64Data, 'PNG', xPos, yPos, imgWidth, imgHeight);
                yPos += imgHeight + 15;
            } catch (e) {
                console.error("Error adding image to PDF", e);
            }
            return;
        }

        // Text Formatting Analysis
        let textToPrint = trimmed;
        let isHeading = false;
        let headingLevel = 0;
        let fontSize = 11;
        let fontStyle = "normal";
        let color = THEME.text; // Default text color

        if (trimmed.startsWith('# ')) {
            isHeading = true;
            headingLevel = 1;
            textToPrint = trimmed.replace('# ', '');
            fontStyle = "bold";
            fontSize = 16;
            color = THEME.accent; // Orange for H1
        } else if (trimmed.startsWith('## ')) {
            isHeading = true;
            headingLevel = 2;
            textToPrint = trimmed.replace('## ', '');
            fontStyle = "bold";
            fontSize = 14;
            color = THEME.accentSecondary; // Amber for H2
        } else if (trimmed.startsWith('### ')) {
            isHeading = true;
            headingLevel = 3;
            textToPrint = trimmed.replace('### ', '');
            fontStyle = "bold";
            fontSize = 12;
            color = THEME.textBold; // White for H3
        } else if (trimmed.startsWith('**')) {
            // Bold lines (like MO Tables keys)
            fontStyle = "bold";
            color = THEME.textBold;
        } else if (trimmed.startsWith('- ') || trimmed.startsWith('* ')) {
            textToPrint = '•  ' + trimmed.substring(2);
        }

        // Clean up markdown bold syntax for rendering
        textToPrint = textToPrint.replace(/\*\*/g, '');

        // Setup Font
        doc.setFont("helvetica", fontStyle);
        doc.setFontSize(fontSize);
        doc.setTextColor(color[0], color[1], color[2]);

        const splitText = doc.splitTextToSize(textToPrint, maxLineWidth);
        const lineHeight = isHeading ? fontSize * 0.7 : 6;
        const blockHeight = splitText.length * lineHeight;
        const extraSpacing = isHeading ? 4 : 2;

        // Pagination Check
        checkPageBreak(blockHeight + extraSpacing);

        // Visual Decorative Element for Headers
        if (headingLevel === 1) {
             // Draw a small colored block next to H1
             doc.setFillColor(THEME.accent[0], THEME.accent[1], THEME.accent[2]);
             doc.rect(margin - 4, yPos + 1, 2, fontSize - 2, 'F');
        }

        // Render Text
        splitText.forEach((textLine: string) => {
             // Safety check per line in case a paragraph is huge
             if (yPos + lineHeight > pageHeight - margin) {
                doc.addPage();
                drawPageBackground();
                yPos = 30;
                doc.setFont("helvetica", fontStyle);
                doc.setFontSize(fontSize);
                doc.setTextColor(color[0], color[1], color[2]);
             }
             doc.text(textLine, margin, yPos);
             yPos += lineHeight;
        });

        yPos += extraSpacing;
    });

    doc.save(`${subtitle.replace(/\s+/g, '_')}.pdf`);
};

// Helper for DOCX
const parseBoldText = (text: string): TextRun[] => {
    const parts: TextRun[] = [];
    const regex = /\*\*(.*?)\*\*/g;
    let lastIndex = 0;
    let match;

    while ((match = regex.exec(text)) !== null) {
        if (match.index > lastIndex) {
            parts.push(new TextRun(text.substring(lastIndex, match.index)));
        }
        parts.push(new TextRun({
            text: match[1],
            bold: true,
        }));
        lastIndex = regex.lastIndex;
    }
    if (lastIndex < text.length) {
        parts.push(new TextRun(text.substring(lastIndex)));
    }
    return parts;
};

const saveBlob = (blob: Blob, fileName: string) => {
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement("a");
    document.body.appendChild(a);
    a.style.display = "none";
    a.href = url;
    a.download = fileName;
    a.click();
    window.URL.revokeObjectURL(url);
    document.body.removeChild(a);
};

