const getUIScreens = async (context: string): Promise<GeneratedArtifact> => {
    const uiPrompt = `Atue como um Diretor de Arte de UI Design. Sua tarefa é escrever um prompt de geração de imagem textual altamente detalhado para criar uma tela de interface de alta fidelidade.

Considere as personas, o fluxo e os requisitos.
A resposta DEVE ser um objeto JSON com o campo "imagePrompt".

O "imagePrompt" deve descrever a tela visualmente para um modelo de IA generativa (como Imagen ou Midjourney):
- Descreva o tipo de tela (ex: Dashboard, Login, Feed, Detalhe de Produto).
- Defina o estilo visual (ex: Neomorfismo, Material Design, Minimalista, Dark Mode, Cores vibrantes).
- Descreva elementos específicos: Tipografia (Sans-serif, bold headers), Botões (arredondados, gradiente), Ícones (outline, filled).
- Descreva o conteúdo fictício visível para tornar a tela realista.

Contexto do Projeto: ${context}`;

    let uiData;
    const maxRetries = 2;

    for (let attempt = 1; attempt <= maxRetries; attempt++) {
        try {
            const uiResponse = await ai.models.generateContent({
                model: "gemini-2.5-pro",
                contents: uiPrompt,
                config: {
                  responseMimeType: "application/json",
                  responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                      imagePrompt: { type: Type.STRING },
                    }
                  }
                }
            });

            const parsedData = safeParseJson(uiResponse.text);

            if (parsedData && typeof parsedData.imagePrompt === 'string' && parsedData.imagePrompt.trim()) {
                uiData = parsedData;
                break; // Success
            } else {
                console.warn(`Attempt ${attempt} failed: Invalid UI screen data.`, parsedData);
            }
        } catch (error) {
            console.error(`Attempt ${attempt} failed with error:`, error);
        }

        if (attempt < maxRetries) {
            console.log(`Retrying UI screen generation... (${attempt}/${maxRetries})`);
        }
    }

    if (!uiData) {
        console.error("Failed to generate valid UI screen data after all retries.");
        throw new Error("A resposta do modelo para a tela de UI veio incompleta, mesmo após tentar novamente.");
    }

    const finalImagePrompt = `Mobile app UI screen design, high fidelity, HQ, 4k. ${uiData.imagePrompt}`;

    const imageResponse = await ai.models.generateImages({
        model: 'imagen-4.0-generate-001',
        prompt: finalImagePrompt,
        config: {
          numberOfImages: 1,
          aspectRatio: "9:16",
        }
    });

    const base64Image = imageResponse.generatedImages[0].image.imageBytes;
    const imageUrl = `data:image/png;base64,${base64Image}`;

    return { text: "Aqui está uma proposta de UI para a tela solicitada, baseada em todo o contexto do projeto.", imageUrl };
};

export const generateArtifact = async (artifactType: ArtifactType, context: string): Promise<GeneratedArtifact> => {
    switch (artifactType) {
        case ArtifactType.Observation:
            return getObservationSummary(context);
        case ArtifactType.InterviewQuestions:
            return getInterviewQuestions(context);
        case ArtifactType.SummarizeInterview:
            return getInterviewSummary(context);
        case ArtifactType.MOTables:
            return getMOTables(context);
        case ArtifactType.Personas:
            return getPersona(context);
        case ArtifactType.AgentModel:
            return getAgentModel(context);
        case ArtifactType.EmpathyMap:
            return getEmpathyMap(context);
        case ArtifactType.HypothesisGeneration:
            return getHypotheses(context);
        case ArtifactType.UserFlows:
            return getUserFlows(context);
        case ArtifactType.UIScreens:
            return getUIScreens(context);
        default:
            throw new Error('Tipo de artefato desconhecido');
    }
};

import { Document, Packer, Paragraph, TextRun, HeadingLevel, AlignmentType, ImageRun } from "docx";
import { jsPDF } from "jspdf";

// App Theme Colors for PDF
const THEME = {
    bg: [9, 9, 11],         // Zinc 950
    cardBg: [24, 24, 27],   // Zinc 900
    text: [228, 228, 231],  // Zinc 200 (Brighter for better contrast)
    textBold: [255, 255, 255], // White
    accent: [249, 115, 22], // Orange 500
    accentSecondary: [251, 191, 36], // Amber 400
    border: [63, 63, 70]    // Zinc 700
};

export const generateAndDownloadDocx = async (title: string, subtitle: string, content: string) => {
    const lines = content.split('\n');
    const docChildren: (Paragraph)[] = [];

    // Title
    docChildren.push(
        new Paragraph({
            text: title,
            heading: HeadingLevel.TITLE,
            alignment: AlignmentType.CENTER,
            spacing: { after: 300 },
        })
    );

    // Subtitle
    docChildren.push(
        new Paragraph({
            text: subtitle,
            heading: HeadingLevel.HEADING_2,
            alignment: AlignmentType.CENTER,
            spacing: { after: 300 },
        })
    );

    // Process Content
    // Captures: 1=AltText, 2=FullDataURI, 3=MimeSubtype (e.g., png, jpeg)
    const imageRegex = /!\[(.*?)\]\((data:image\/(.*?);base64,.*?)\)/;

    for (const line of lines) {
        const trimmed = line.trim();
        if (!trimmed) {
            docChildren.push(new Paragraph({ text: "" }));
            continue;
        }

        const imageMatch = trimmed.match(imageRegex);

        if (imageMatch) {
            try {
                const fullDataUri = imageMatch[2];
                const mimeType = imageMatch[3].toLowerCase();
                const base64Data = fullDataUri.split(',')[1];

                const imageBuffer = Uint8Array.from(atob(base64Data), c => c.charCodeAt(0));

                // Map mime subtype to docx valid types
                // IImageRun type: "png" | "jpeg" | "gif" | "bmp" | "svg"
                let imgType: "png" | "jpeg" | "gif" | "bmp" | "svg" = "png";
                if (mimeType === 'jpg' || mimeType === 'jpeg') {
                    imgType = "jpeg";
                } else if (mimeType === 'svg+xml' || mimeType === 'svg') {
                    imgType = "svg";
                }

                docChildren.push(new Paragraph({
                    children: [
                        new ImageRun({
                            data: imageBuffer,
                            transformation: {
                                width: 300,
                                height: 300,
                            },
                            type: imgType
                        })
                    ],
                    alignment: AlignmentType.CENTER,
                    spacing: { before: 200, after: 200 }
                }));
            } catch (e) {
                console.error("Error embedding image in Docx", e);
            }
            continue;
        }

        if (trimmed.startsWith('### ')) {
            docChildren.push(new Paragraph({
                text: trimmed.replace('### ', ''),
                heading: HeadingLevel.HEADING_3,
                spacing: { before: 200, after: 100 }
            }));
        } else if (trimmed.startsWith('## ')) {
            docChildren.push(new Paragraph({
                text: trimmed.replace('## ', ''),
                heading: HeadingLevel.HEADING_2,
                spacing: { before: 240, after: 120 }
            }));
        } else if (trimmed.startsWith('# ')) {
            docChildren.push(new Paragraph({
                text: trimmed.replace('# ', ''),
                heading: HeadingLevel.HEADING_1,
                spacing: { before: 280, after: 140 }
            }));
        } else if (trimmed.startsWith('- ') || trimmed.startsWith('* ')) {
             const textContent = trimmed.substring(2);
             const parts = parseBoldText(textContent);

             docChildren.push(new Paragraph({
                children: parts,
                bullet: { level: 0 }
            }));
        } else {
            const parts = parseBoldText(trimmed);
            docChildren.push(new Paragraph({
                children: parts,
                spacing: { after: 120 }
            }));
        }
    }

    const doc = new Document({
        sections: [{
            properties: {},
            children: docChildren,
        }],
    });

    const blob = await Packer.toBlob(doc);
    saveBlob(blob, `${subtitle.replace(/\s+/g, '_')}.docx`);
};

export const generateAndDownloadPdf = (title: string, subtitle: string, content: string) => {
    const doc = new jsPDF();
    const pageWidth = doc.internal.pageSize.getWidth();
    const pageHeight = doc.internal.pageSize.getHeight();
    const margin = 20; 
    const maxLineWidth = pageWidth - (margin * 2);
    let yPos = 20;

    // --- Helper Functions for Theme ---

    const drawPageBackground = () => {
        // Fill Page Background
        doc.setFillColor(THEME.bg[0], THEME.bg[1], THEME.bg[2]);
        doc.rect(0, 0, pageWidth, pageHeight, 'F');

        // Draw Header Line / App Branding
        doc.setDrawColor(THEME.accent[0], THEME.accent[1], THEME.accent[2]);
        doc.setLineWidth(0.5);
        doc.line(margin, 15, pageWidth - margin, 15);

        // Note: This changes the font settings globally on the new page
        doc.setFontSize(8);
        doc.setTextColor(THEME.accentSecondary[0], THEME.accentSecondary[1], THEME.accentSecondary[2]);
        doc.setFont("helvetica", "bold");
        doc.text("AGENTE UX", margin, 12);

        doc.setTextColor(100, 100, 100);
        doc.setFont("helvetica", "normal");
        doc.text(new Date().toLocaleDateString(), pageWidth - margin, 12, { align: "right" });
    };

    const checkPageBreak = (heightNeeded: number) => {
        if (yPos + heightNeeded > pageHeight - margin) {
            doc.addPage();
            drawPageBackground();
            yPos = 30; // Start lower on new pages
            return true;
        }
        return false;
    };

    // --- Initial Page Setup ---
    drawPageBackground();
    yPos = 30;

    // Document Title
    doc.setFontSize(22);
    doc.setTextColor(THEME.accent[0], THEME.accent[1], THEME.accent[2]);
    doc.setFont("helvetica", "bold");

    // Wrap title text
    const splitTitle = doc.splitTextToSize(title, maxLineWidth);
    splitTitle.forEach((line: string) => {
        doc.text(line, pageWidth / 2, yPos, { align: "center" });
        yPos += 10;
    });
    yPos += 5;

    // Document Subtitle
    doc.setFontSize(16);
    doc.setTextColor(THEME.textBold[0], THEME.textBold[1], THEME.textBold[2]);
    doc.setFont("helvetica", "normal");

    // Wrap subtitle text
    const splitSubtitle = doc.splitTextToSize(subtitle, maxLineWidth);
    splitSubtitle.forEach((line: string) => {
        doc.text(line, pageWidth / 2, yPos, { align: "center" });
        yPos += 8;
    });
    yPos += 20;

    // Draw separator after title
    doc.setDrawColor(THEME.border[0], THEME.border[1], THEME.border[2]);
    doc.line(margin, yPos - 10, pageWidth - margin, yPos - 10);

    // Set Default Body Font Size
    const BODY_FONT_SIZE = 10;
    const HEADER_1_SIZE = 16;
    const HEADER_2_SIZE = 14;
    const HEADER_3_SIZE = 12;

    doc.setFontSize(BODY_FONT_SIZE);

    const lines = content.split('\n');

    // Captures: 1=AltText, 2=FullDataURI, 3=MimeSubtype (e.g., png, jpeg)
    const imageRegex = /!\[(.*?)\]\((data:image\/(.*?);base64,.*?)\)/;

    // Regex to handle bullets or numbers with bold keys:
    // Captures: 1=(Marker), 2=(Key), 3=(Content)
    const boldListItemRegex = /^([-*]|\d+\.)\s+\*\*(.*?)\*\*:?\s*(.*)$/;

    lines.forEach(line => {
        const trimmed = line.trim();

        if (!trimmed) {
            yPos += 4;
            checkPageBreak(5);
            return;
        }

        // Image Handling
        const imageMatch = trimmed.match(imageRegex);
        if (imageMatch) {
            try {
                const fullDataUri = imageMatch[2];
                const mimeType = imageMatch[3].toLowerCase();

                const imgHeight = 90; 
                const imgWidth = 90;

                checkPageBreak(imgHeight + 10);

                const xPos = (pageWidth - imgWidth) / 2;

                // Draw a frame for the image
                doc.setDrawColor(THEME.border[0], THEME.border[1], THEME.border[2]);
                doc.setFillColor(THEME.cardBg[0], THEME.cardBg[1], THEME.cardBg[2]);
                doc.roundedRect(xPos - 2, yPos - 2, imgWidth + 4, imgHeight + 4, 3, 3, 'FD');

                // Determine PDF format from mime type
                let format = 'PNG';
                if (mimeType === 'jpg' || mimeType === 'jpeg') format = 'JPEG';
                if (mimeType === 'webp') format = 'WEBP';

                doc.addImage(fullDataUri, format, xPos, yPos, imgWidth, imgHeight);
                yPos += imgHeight + 15;
            } catch (e) {
                console.error("Error adding image to PDF", e);
            }
            return;
        }

        // 1. HEADINGS
        // Critical: We must set font settings AFTER checkPageBreak, because drawPageBackground resets font size to 8.
        if (trimmed.startsWith('# ')) {
            const textToPrint = trimmed.replace('# ', '').replace(/\*\*/g, '');
            checkPageBreak(HEADER_1_SIZE);

            // Re-apply settings
            doc.setFont("helvetica", "bold");
            doc.setFontSize(HEADER_1_SIZE);
            doc.setTextColor(THEME.accent[0], THEME.accent[1], THEME.accent[2]);

            // Decorative vertical bar REMOVED

            doc.text(textToPrint, margin, yPos + 4);
            yPos += HEADER_1_SIZE;
            return;
        } 

        if (trimmed.startsWith('## ')) {
            const textToPrint = trimmed.replace('## ', '').replace(/\*\*/g, '');
            checkPageBreak(HEADER_2_SIZE);

            // Re-apply settings
            doc.setFont("helvetica", "bold");
            doc.setFontSize(HEADER_2_SIZE);
            doc.setTextColor(THEME.accentSecondary[0], THEME.accentSecondary[1], THEME.accentSecondary[2]);

            doc.text(textToPrint, margin, yPos + 3);
            yPos += HEADER_2_SIZE;
            return;
        }

        if (trimmed.startsWith('### ')) {
            const textToPrint = trimmed.replace('### ', '').replace(/\*\*/g, '');
            checkPageBreak(HEADER_3_SIZE);

            // Re-apply settings
            doc.setFont("helvetica", "bold");
            doc.setFontSize(HEADER_3_SIZE);
            doc.setTextColor(THEME.textBold[0], THEME.textBold[1], THEME.textBold[2]);

            doc.text(textToPrint, margin, yPos + 2);
            yPos += HEADER_3_SIZE;
            return;
        }

        // 1.5 SPECIAL MO TABLE HEADERS (Orange and Bold)
        // Check for specific headers that are not standard list items but are bold
        // e.g., "**Problemas e Oportunidades:**"
        const boldHeaderMatch = trimmed.match(/^\*\*(.*?)\*\*:?\s*(.*)$/);
        if (boldHeaderMatch) {
            let key = boldHeaderMatch[1].trim();
            // FIX: Remove trailing colon if it was captured inside the bold tags
            if (key.endsWith(':')) {
                key = key.slice(0, -1);
            }

            const content = boldHeaderMatch[2].trim();

            const ORANGE_TITLES = [
                "Problemas e Oportunidades",
                "Contexto Geral",
                "Fatores Externos",
                "Soluções Potenciais",
                "Aplicabilidade do Negócio",
                "Aplicabilidade Técnica",
                "Aplicabilidade do Projeto",
                "Riscos do Projeto",
                "Ações"
            ];

            // Check if it is one of the target titles
            if (ORANGE_TITLES.some(t => key.toLowerCase() === t.toLowerCase() || key.includes(t))) {
                checkPageBreak(HEADER_3_SIZE + 4);

                // Render Title in Orange/Bold
                doc.setFont("helvetica", "bold");
                doc.setFontSize(HEADER_3_SIZE); // Use H3 size
                doc.setTextColor(THEME.accent[0], THEME.accent[1], THEME.accent[2]); // Orange
                doc.text(key + ":", margin, yPos + 2);
                yPos += HEADER_3_SIZE;

                // If content exists on same line, print it
                if (content) {
                     doc.setFont("helvetica", "normal");
                     doc.setFontSize(BODY_FONT_SIZE);
                     doc.setTextColor(THEME.text[0], THEME.text[1], THEME.text[2]);

                     const lineHeight = 5.5;
                     const splitContent = doc.splitTextToSize(content, maxLineWidth);
                     splitContent.forEach((textLine: string) => {
                         if (yPos + lineHeight > pageHeight - margin) {
                            doc.addPage();
                            drawPageBackground();
                            yPos = 30;
                            // Reset settings
                            doc.setFont("helvetica", "normal");
                            doc.setFontSize(BODY_FONT_SIZE);
                            doc.setTextColor(THEME.text[0], THEME.text[1], THEME.text[2]);
                         }
                         doc.text(textLine, margin, yPos);
                         yPos += lineHeight;
                     });
                     yPos += 2;
                }
                return;
            }
        }

        // 2. LIST ITEMS WITH BOLD KEYS (Render: Title on Line 1, Content on Line 2)
        const boldItemMatch = trimmed.match(boldListItemRegex);
        if (boldItemMatch) {
            // Group 2 is the Key. Fix potential double colon by removing it from key if present.
            const rawTitle = boldItemMatch[2].trim().replace(/:$/, '');
            const title = rawTitle + ":"; 

            const content = boldItemMatch[3].trim();

            const lineHeight = 5.5;

            // Set font to Body temporarily to calculate content lines height
            doc.setFontSize(BODY_FONT_SIZE);
            doc.setFont("helvetica", "normal");
            const contentLines = doc.splitTextToSize(content, maxLineWidth);

            const totalBlockHeight = lineHeight + (contentLines.length * lineHeight);

            checkPageBreak(totalBlockHeight + 2);

            // Render Title (Line 1 - Bold/White)
            doc.setFont("helvetica", "bold");
            doc.setFontSize(BODY_FONT_SIZE); // Ensure size is correct
            doc.setTextColor(THEME.textBold[0], THEME.textBold[1], THEME.textBold[2]);
            doc.text(title, margin, yPos);

            // Move to next line for content
            yPos += lineHeight;

            // Render Content (Line 2+ - Normal/Gray)
            doc.setFont("helvetica", "normal");
            doc.setFontSize(BODY_FONT_SIZE); // Ensure size is correct
            doc.setTextColor(THEME.text[0], THEME.text[1], THEME.text[2]);
            doc.text(contentLines, margin, yPos);

            // Spacing after item
            yPos += (contentLines.length * lineHeight) + 2;
            return;
        }

        // 3. STANDARD PARAGRAPHS & PLAIN LISTS
        // Strip remaining markdown bold syntax for clean printing
        let textToPrint = trimmed.replace(/\*\*/g, '');

        // Remove list markers (bullets or numbers) to flatten the look
        if (textToPrint.startsWith('- ') || textToPrint.startsWith('* ')) {
            textToPrint = textToPrint.substring(2);
        } else if (/^\d+\.\s/.test(textToPrint)) {
            textToPrint = textToPrint.replace(/^\d+\.\s/, '');
        }

        // Set font for calculation
        doc.setFont("helvetica", "normal");
        doc.setFontSize(BODY_FONT_SIZE);

        const lineHeight = 5.5; 
        const splitText = doc.splitTextToSize(textToPrint, maxLineWidth);
        const blockHeight = splitText.length * lineHeight;

        checkPageBreak(blockHeight + 2);

        // FIX: Re-apply font settings here because checkPageBreak might have changed them to size 8 (header style)
        doc.setFont("helvetica", "normal");
        doc.setFontSize(BODY_FONT_SIZE);
        doc.setTextColor(THEME.text[0], THEME.text[1], THEME.text[2]);

        splitText.forEach((textLine: string) => {
             if (yPos + lineHeight > pageHeight - margin) {
                doc.addPage();
                drawPageBackground();
                yPos = 30;

                // Re-apply settings if we break inside a paragraph
                doc.setFont("helvetica", "normal");
                doc.setFontSize(BODY_FONT_SIZE);
                doc.setTextColor(THEME.text[0], THEME.text[1], THEME.text[2]);
             }
             doc.text(textLine, margin, yPos);
             yPos += lineHeight;
        });

        yPos += 2;
    });

    doc.save(`${subtitle.replace(/\s+/g, '_')}.pdf`);
};

// Helper for DOCX
const parseBoldText = (text: string): TextRun[] => {
    const parts: TextRun[] = [];
    const regex = /\*\*(.*?)\*\*/g;
    let lastIndex = 0;
    let match;

    while ((match = regex.exec(text)) !== null) {
        if (match.index > lastIndex) {
            parts.push(new TextRun(text.substring(lastIndex, match.index)));
        }
        parts.push(new TextRun({
            text: match[1],
            bold: true,
        }));
        lastIndex = regex.lastIndex;
    }
    if (lastIndex < text.length) {
        parts.push(new TextRun(text.substring(lastIndex)));
    }
    return parts;
};

const saveBlob = (blob: Blob, fileName: string) => {
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement("a");
    document.body.appendChild(a);
    a.style.display = "none";
    a.href = url;
    a.download = fileName;
    a.click();
    window.URL.revokeObjectURL(url);
    document.body.removeChild(a);
};
